阅读以下用动态规划解决的 0-1 背包问题的函数，假设背包的容量是 $10$ kg，假设输入 $4$ 个物品的重量分别为（单位为 kg），每个物品对应的价值分别为，则函数的输出为（ ）。

```cpp
#include <iostream>
#include <vector>
using namespace std;
// 0/1 背包问题
int knapsack(int W, const vector<int>& weights, const vector<int>& values, int n) {
    vector<vector<int>> dp(n + 1, vector<int>(W + 1, 0));
    for (int i = 1; i <= n; ++i) {
        for (int w = 0; w <= W; ++w) {
            if (weights[i - 1] <= w) {
                dp[i][w] = max(dp[i - 1][w], dp[i - 1][w - weights[i - 1]] + values[i - 1]);
            } else {
                dp[i][w] = dp[i - 1][w];
            }
        }
    }
    return dp[n][W];
}
```

运行以下 C++ 代码，屏幕将输出“derived class”。

```cpp
#include <iostream>
using namespace std;
class base {
    public:
    virtual void show() {
        cout << "base class" << endl;
    }
};
class derived : public base {
    public:
    void show() override {
        cout << "derived class" << endl;
    }
};
int main() {
    base* b;
    derived d;
    b = &d;
    b->show();
    return 0;
}
```

如下列代码所示的基类（base）及其派生类（derived），则生成一个派生类的对象时，只调用派生类的构造函数。

```cpp
